from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Find the main subject (likely an airport)
    main_subject = None
    for subject in subject_map.keys():
        if any(p in ["cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel", "icaoLocationIdentifier", "iataLocationIdentifier"] for p, _ in subject_map[subject]):
            main_subject = subject
            break

    if not main_subject and subject_map:
        main_subject = list(subject_map.keys())[0]

    if not main_subject:
        return "."

    # Collect all information for the main subject and related entities
    clauses = []
    related_entities = {}  # Track entities that are connected to the main subject

    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if predicate == "cityServed":
                clauses.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                clauses.append(f"has a mayor named {obj}")
            elif predicate == "isPartOf":
                if subject == main_subject:
                    clauses.append(f"is part of {obj}")
                else:
                    related_entities[subject] = f"is part of {obj}"
            elif predicate == "operatingOrganisation":
                clauses.append(f"is operated by {obj}")
            elif predicate == "location":
                if subject == main_subject:
                    clauses.append(f"is located in {obj}")
                    # Track location for potential country connection
                    related_entities[obj] = "location"
                else:
                    clauses.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                clauses.append(f"is {obj} metres above sea level")
            elif predicate == "runwayLength":
                clauses.append(f"has a runway length of {obj} metres")
            elif predicate == "country":
                if subject == main_subject:
                    clauses.append(f"is located in {obj}")
                elif subject in related_entities and related_entities[subject] == "location":
                    # This is the country of the location
                    clauses.append(f"which is in {obj}")
                else:
                    clauses.append(f"has {obj} as its country")
            elif predicate == "capital":
                clauses.append(f"has {obj} as its capital")
            elif predicate == "language":
                if subject == main_subject:
                    clauses.append(f"has {obj} as its language")
                elif subject in related_entities and related_entities[subject] == "location":
                    clauses.append(f"where {obj} is spoken")
            elif predicate == "leader":
                clauses.append(f"has {obj} as its leader")
            elif predicate == "owner":
                clauses.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                clauses.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                clauses.append(f"has a first runway made of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                clauses.append(f"has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                clauses.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                clauses.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                clauses.append(f"is {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                clauses.append(f"has an IATA identifier of {obj}")
            elif predicate == "nativeName":
                clauses.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                clauses.append(f"has a leader party of {obj}")
            elif predicate == "runwayName":
                clauses.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                clauses.append(f"has a runway made of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                clauses.append(f"is {obj} metres above sea level")
            elif predicate == "officialLanguage":
                clauses.append(f"has {obj} as its official language")
            elif predicate == "demonym":
                clauses.append(f"whose people are called {obj}")
            else:
                clauses.append(f"has a {predicate} of {obj}")

    # Construct a single complex sentence
    if clauses:
        # Use the main subject as the start
        sentence = main_subject + " " + ", ".join(clauses)
    else:
        sentence = main_subject

    return sentence + "."

